import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const SEMESTERS = [1,2,3,4,5,6,7,8];

/* ── Library loaders ─────────────────────────────────────── */
async function loadXLSX() { if(window.XLSX)return window.XLSX; await new Promise((r,j)=>{const s=document.createElement('script');s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';s.onload=r;s.onerror=j;document.head.appendChild(s);}); return window.XLSX; }

async function exportExcel(sheets, filename) {
  const XLSX = await loadXLSX();
  const wb   = XLSX.utils.book_new();
  sheets.forEach(({ name, data }) => {
    const ws = XLSX.utils.aoa_to_sheet(data);
    ws['!cols'] = data[0]?.map((_,ci) => ({ wch: Math.max(...data.map(r => String(r[ci]??'').length), 10) }));
    XLSX.utils.book_append_sheet(wb, ws, name.slice(0,31));
  });
  XLSX.writeFile(wb, filename);
}

async function loadJsPDF() {
  if(window.jspdf) return window.jspdf.jsPDF;
  await new Promise((r,j)=>{const s=document.createElement('script');s.src='https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';s.onload=r;s.onerror=j;document.head.appendChild(s);});
  await new Promise((r,j)=>{const s=document.createElement('script');s.src='https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.5.31/jspdf.plugin.autotable.min.js';s.onload=r;s.onerror=j;document.head.appendChild(s);});
  return window.jspdf.jsPDF;
}

async function exportPDF(title, subtitle, head, body, filename) {
  const JsPDF = await loadJsPDF();
  const doc   = new JsPDF({ orientation:'landscape' });
  const pw    = doc.internal.pageSize.width;
  doc.setFontSize(16); doc.setFont('helvetica','bold');
  doc.text('VEMU Institute of Technology', pw/2, 14, { align:'center' });
  doc.setFontSize(11); doc.setFont('helvetica','normal');
  doc.text(title,    pw/2, 22, { align:'center' });
  doc.setFontSize(9);
  doc.text(subtitle, pw/2, 28, { align:'center' });
  doc.text(`Generated: ${new Date().toLocaleDateString('en-IN')}`, pw/2, 34, { align:'center' });
  doc.autoTable({ startY:40, head:[head], body, styles:{fontSize:7.5,cellPadding:2}, headStyles:{fillColor:[26,86,219],textColor:255,fontStyle:'bold'}, alternateRowStyles:{fillColor:[241,245,249]}, margin:{left:8,right:8} });
  doc.save(filename);
}

export default function AdminReports() {
  const [loading,  setLoading]  = useState(false);
  const [depts,    setDepts]    = useState([]);
  const [subjects, setSubjects] = useState([]);
  const [sections, setSections] = useState([]);

  // Filters
  const [selDept, setSelDept] = useState('');
  const [selSem,  setSelSem]  = useState('');
  const [selSec,  setSelSec]  = useState('');
  const [selSubj, setSelSubj] = useState('');
  const [selExam, setSelExam] = useState('');

  useEffect(() => {
    axios.get('/api/admin/departments').then(r => setDepts(r.data.departments?.filter(d=>d.isActive)||[]));
  }, []);

  // Load subjects when dept+sem changes
  useEffect(() => {
    if (!selSem) { setSubjects([]); setSelSubj(''); return; }
    axios.get('/api/admin/subjects').then(r => {
      const filtered = r.data.subjects?.filter(s =>
        (!selDept || s.department?._id === selDept) &&
        s.semester === Number(selSem)
      ) || [];
      setSubjects(filtered);
      setSelSubj('');
    });
  }, [selDept, selSem]);

  // Load sections when dept+sem changes
  useEffect(() => {
    if (!selSem) { setSections([]); setSelSec(''); return; }
    // Get sections from admin sections endpoint
    axios.get('/api/admin/sections', { params: { ...(selDept?{department:selDept}:{}), semester:selSem } })
      .then(r => { setSections(r.data.sections||[]); setSelSec(''); })
      .catch(() => setSections([]));
  }, [selDept, selSem]);

  const clearFilters = () => { setSelDept(''); setSelSem(''); setSelSec(''); setSelSubj(''); setSelExam(''); };

  const wrap = async fn => { setLoading(true); try { await fn(); } catch(e) { toast.error('Export failed: '+e.message); } finally { setLoading(false); } };

  /* ── Apply filters to marks array ── */
  const applyFilters = (marks) => {
    let d = [...marks];
    // Only include students who are CURRENTLY in this semester (not promoted away)
    if (selSem)  d = d.filter(m => m.semester === Number(selSem) && m.student?.semester === Number(selSem));
    if (selDept) d = d.filter(m => m.department === selDept || m.student?.department?._id === selDept);
    if (selSec)  d = d.filter(m => m.student?.section === selSec);
    if (selSubj) d = d.filter(m => m.subject?._id === selSubj);
    if (selExam) d = d.filter(m => m.midExam === selExam);
    return d;
  };

  const getLabel = () => {
    const parts = [];
    if (selDept) parts.push(depts.find(d=>d._id===selDept)?.code||'');
    if (selSem)  parts.push(`Sem${selSem}`);
    if (selSec)  parts.push(`Sec${selSec}`);
    if (selExam) parts.push(selExam.replace('-',''));
    return parts.join('_') || 'All';
  };

  const getSubtitle = () => {
    const parts = [];
    if (selDept) parts.push(depts.find(d=>d._id===selDept)?.name||'All Depts');
    if (selSem)  parts.push(`Semester ${selSem}`);
    if (selSec)  parts.push(`Section ${selSec}`);
    if (selSubj) parts.push(subjects.find(s=>s._id===selSubj)?.name||'');
    if (selExam) parts.push(selExam);
    return parts.join(' | ') || 'All Data';
  };

  const excelClassWise = () => wrap(async () => {
    if (!selSem) return toast.error('Select at least a Semester');
    const r = await axios.get('/api/admin/marks');
    const filtered = applyFilters(r.data.marks);
    if (!filtered.length) return toast.error('No data found for selected filters');

    const mid1 = filtered.filter(m=>m.midExam==='Mid-1');
    const mid2 = filtered.filter(m=>m.midExam==='Mid-2');
    const col = ['#','Student','Roll No','Department','Semester','Section','Subject','Code','Asgn/5','SHA/10','Q1','Q2','Q3','Q4','Q5','Q6','Best Q1/Q2','Best Q3/Q4','Best Q5/Q6','Q-Half/15','Total/30','Faculty','Status'];

    const makeRows = arr => arr.map((m,i)=>[
      i+1, m.student?.name||'—', m.student?.rollNumber||'—', m.student?.department?.name||'—',
      m.semester, m.student?.section||'—', m.subject?.name||'—', m.subject?.code||'—',
      m.assignmentMarks, m.shaMarks, m.q1, m.q2, m.q3, m.q4, m.q5, m.q6,
      m.bestQ1Q2, m.bestQ3Q4, m.bestQ5Q6, m.questionHalf, m.totalMarks, m.faculty?.name||'—', m.status
    ]);

    const sheets = [];
    const label  = getLabel();

    if (!selExam || selExam==='Mid-1') sheets.push({ name:`${label} Mid-1`, data:[
      [`VEMU — Class Report — ${getSubtitle()} — Mid-1`],
      [`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
      col, ...makeRows(mid1.length ? mid1 : filtered.filter(m=>m.midExam==='Mid-1'))
    ]});
    if (!selExam || selExam==='Mid-2') sheets.push({ name:`${label} Mid-2`, data:[
      [`VEMU — Class Report — ${getSubtitle()} — Mid-2`],
      [`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
      col, ...makeRows(mid2.length ? mid2 : filtered.filter(m=>m.midExam==='Mid-2'))
    ]});
    if (!sheets.some(s=>s.data.length>4)) return toast.error('No marks data found');

    await exportExcel(sheets, `VEMU_ClassReport_${label}.xlsx`);
    toast.success('Excel downloaded!');
  });

  const pdfClassWise = () => wrap(async () => {
    if (!selSem) return toast.error('Select at least a Semester');
    const r = await axios.get('/api/admin/marks');
    const filtered = applyFilters(r.data.marks);
    if (!filtered.length) return toast.error('No data found for selected filters');

    await exportPDF(
      `Class-wise Marks Report`,
      getSubtitle(),
      ['#','Student','Roll No','Dept','Sem','Sec','Subject','Exam','Asgn/5','SHA/10','Q-Half/15','Total/30','Faculty','Status'],
      filtered.map((m,i)=>[
        i+1, m.student?.name||'—', m.student?.rollNumber||'—', m.student?.department?.name||'—',
        m.semester, m.student?.section||'—', m.subject?.name||'—', m.midExam,
        m.assignmentMarks, m.shaMarks, m.questionHalf, m.totalMarks, m.faculty?.name||'—', m.status
      ]),
      `VEMU_ClassReport_${getLabel()}.pdf`
    );
    toast.success('PDF downloaded!');
  });

  const hasFilters = selDept||selSem||selSec||selSubj||selExam;

  return (
    <div>
      <div className="page-header">
        <div><div className="page-title">📋 Reports</div><div className="page-subtitle">Generate class-wise and subject-wise reports</div></div>
      </div>

      <div className="card">
        <div className="card-header">
          <span className="card-title">📚 Class-wise / Subject Report</span>
        </div>
        <div className="card-body">
          <p style={{ color:'var(--text-muted)',fontSize:13,marginBottom:16 }}>
            Filter by department, semester, section, subject and exam to generate targeted reports.
            Reports only include students currently enrolled in the selected semester.
          </p>

          {/* Filters — single line */}
          <div style={{ display:'flex', gap:8, flexWrap:'wrap', marginBottom:16, alignItems:'flex-end' }}>
            <div>
              <label style={{ fontSize:11,fontWeight:600,display:'block',marginBottom:4,color:'var(--text-muted)' }}>Department</label>
              <select className="form-select" style={{ width:180,fontSize:12 }} value={selDept} onChange={e=>setSelDept(e.target.value)}>
                <option value="">All Departments</option>
                {depts.map(d=><option key={d._id} value={d._id}>{d.name} ({d.code})</option>)}
              </select>
            </div>
            <div>
              <label style={{ fontSize:11,fontWeight:600,display:'block',marginBottom:4,color:'var(--text-muted)' }}>Semester *</label>
              <select className="form-select" style={{ width:140,fontSize:12 }} value={selSem} onChange={e=>setSelSem(e.target.value)}>
                <option value="">Select Sem</option>
                {SEMESTERS.map(s=><option key={s} value={s}>Semester {s}</option>)}
              </select>
            </div>
            <div>
              <label style={{ fontSize:11,fontWeight:600,display:'block',marginBottom:4,color:'var(--text-muted)' }}>Section</label>
              <select className="form-select" style={{ width:130,fontSize:12 }} value={selSec} onChange={e=>setSelSec(e.target.value)} disabled={!selSem}>
                <option value="">All Sections</option>
                {sections.map(s=><option key={s._id} value={s.name}>Section {s.name}</option>)}
              </select>
            </div>
            <div>
              <label style={{ fontSize:11,fontWeight:600,display:'block',marginBottom:4,color:'var(--text-muted)' }}>Subject</label>
              <select className="form-select" style={{ width:190,fontSize:12 }} value={selSubj} onChange={e=>setSelSubj(e.target.value)} disabled={!selSem}>
                <option value="">All Subjects</option>
                {subjects.map(s=><option key={s._id} value={s._id}>{s.name} ({s.code})</option>)}
              </select>
            </div>
            <div>
              <label style={{ fontSize:11,fontWeight:600,display:'block',marginBottom:4,color:'var(--text-muted)' }}>Exam</label>
              <select className="form-select" style={{ width:120,fontSize:12 }} value={selExam} onChange={e=>setSelExam(e.target.value)}>
                <option value="">Both Mids</option>
                <option value="Mid-1">Mid-1</option>
                <option value="Mid-2">Mid-2</option>
              </select>
            </div>
            {hasFilters && (
              <div style={{ alignSelf:'flex-end' }}>
                <button className="btn btn-outline btn-sm" onClick={clearFilters} style={{ fontSize:11 }}>✕ Clear</button>
              </div>
            )}
          </div>

          {/* Active filter summary */}
          {hasFilters && (
            <div className="info-box" style={{ marginBottom:16, fontSize:12 }}>
              📌 Filters: {getSubtitle()} {selSem && `| Only current Semester ${selSem} students included`}
            </div>
          )}

          {/* Download buttons */}
          <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
            <button className="btn btn-success" onClick={excelClassWise} disabled={loading||!selSem}>
              📊 Download Excel {!selExam?'(Mid-1 + Mid-2 sheets)':selExam==='Mid-1'?'(Mid-1)':'(Mid-2)'}
            </button>
            <button className="btn btn-danger" onClick={pdfClassWise} disabled={loading||!selSem}>
              📄 Download PDF
            </button>
          </div>

          {!selSem && (
            <div className="warning-box" style={{ marginTop:14, marginBottom:0 }}>
              ⚠ Please select a <strong>Semester</strong> to enable downloads
            </div>
          )}
        </div>
      </div>

      {loading && (
        <div style={{ textAlign:'center',padding:24,color:'var(--text-muted)',fontSize:13 }}>
          ⏳ Generating report, please wait...
        </div>
      )}
    </div>
  );
}
